import React from 'react';
import { Card, Stack, Text } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

const getWeatherEmoji = (condition: string): string => {
  const conditionLower = condition.toLowerCase();
  if (conditionLower.includes('sunny') || conditionLower.includes('clear')) return '☀️';
  if (conditionLower.includes('cloudy') || conditionLower.includes('overcast')) return '☁️';
  if (conditionLower.includes('rainy') || conditionLower.includes('rain')) return '🌧️';
  if (conditionLower.includes('snowy') || conditionLower.includes('snow')) return '❄️';
  if (conditionLower.includes('stormy') || conditionLower.includes('thunder')) return '⛈️';
  if (conditionLower.includes('windy') || conditionLower.includes('wind')) return '💨';
  return '🌤️'; // Default partly cloudy
};

export default function WeatherCard(props: Props) {
  const {
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
    unit = 'C',
    forecast,
  } = props;

  const weatherEmoji = getWeatherEmoji(condition);

  return (
    <Card
      variant="surface"
      style={{
        padding: 'var(--ggui-space-lg, 24px)',
        backgroundColor: 'var(--ggui-color-surface, #ffffff)',
        borderColor: 'var(--ggui-color-outline, #e0e0e0)',
      }}
    >
      <Stack direction="vertical" gap="var(--ggui-space-md, 16px)">
        {/* Header: City name */}
        <Text
          variant="headline"
          size="sm"
          style={{
            color: 'var(--ggui-color-onSurface, #000000)',
            fontWeight: 500,
          }}
        >
          {city}
        </Text>

        {/* Current Weather Section */}
        <Stack
          direction="horizontal"
          gap="var(--ggui-space-md, 16px)"
          style={{
            alignItems: 'center',
            padding: 'var(--ggui-space-md, 16px) 0',
            borderBottom: '1px solid var(--ggui-color-outline, #e0e0e0)',
          }}
        >
          {/* Weather emoji/icon */}
          <Text
            style={{
              fontSize: '3.5rem',
              lineHeight: '1',
            }}
          >
            {weatherEmoji}
          </Text>

          {/* Temperature and condition */}
          <Stack direction="vertical" gap="var(--ggui-space-sm, 8px)">
            <Text
              variant="display"
              size="lg"
              style={{
                color: 'var(--ggui-color-onSurface, #000000)',
                fontWeight: 700,
              }}
            >
              {temperature}°{unit}
            </Text>
            <Text
              variant="body"
              size="md"
              style={{
                color: 'var(--ggui-color-onSurfaceVariant, #666666)',
              }}
            >
              {condition}
            </Text>
          </Stack>
        </Stack>

        {/* Weather Details: Humidity & Wind */}
        <Stack
          direction="horizontal"
          gap="var(--ggui-space-lg, 24px)"
          style={{
            padding: 'var(--ggui-space-md, 16px) 0',
            borderBottom: '1px solid var(--ggui-color-outline, #e0e0e0)',
          }}
        >
          {/* Humidity */}
          <Stack direction="vertical" gap="var(--ggui-space-xs, 4px)">
            <Text
              variant="label"
              size="sm"
              style={{
                color: 'var(--ggui-color-onSurfaceVariant, #666666)',
                textTransform: 'uppercase',
                letterSpacing: '0.5px',
              }}
            >
              Humidity
            </Text>
            <Text
              variant="body"
              size="lg"
              style={{
                color: 'var(--ggui-color-onSurface, #000000)',
                fontWeight: 600,
              }}
            >
              {humidity}%
            </Text>
          </Stack>

          {/* Wind Speed */}
          <Stack direction="vertical" gap="var(--ggui-space-xs, 4px)">
            <Text
              variant="label"
              size="sm"
              style={{
                color: 'var(--ggui-color-onSurfaceVariant, #666666)',
                textTransform: 'uppercase',
                letterSpacing: '0.5px',
              }}
            >
              Wind Speed
            </Text>
            <Text
              variant="body"
              size="lg"
              style={{
                color: 'var(--ggui-color-onSurface, #000000)',
                fontWeight: 600,
              }}
            >
              {windSpeed} km/h
            </Text>
          </Stack>
        </Stack>

        {/* 5-Day Forecast */}
        <Stack direction="vertical" gap="var(--ggui-space-sm, 8px)">
          <Text
            variant="label"
            size="sm"
            style={{
              color: 'var(--ggui-color-onSurfaceVariant, #666666)',
              textTransform: 'uppercase',
              letterSpacing: '0.5px',
              paddingTop: 'var(--ggui-space-md, 16px)',
            }}
          >
            5-Day Forecast
          </Text>

          <Stack
            direction="horizontal"
            gap="var(--ggui-space-sm, 8px)"
            style={{
              overflowX: 'auto',
              paddingBottom: 'var(--ggui-space-sm, 8px)',
            }}
          >
            {forecast && forecast.length > 0 ? (
              forecast.map((item, index) => {
                const dayLabel = item.day || 'Day ' + (index + 1);
                return (
                  <Stack
                    key={index}
                    direction="vertical"
                    gap="var(--ggui-space-xs, 4px)"
                    style={{
                      minWidth: '100px',
                      padding: 'var(--ggui-space-sm, 8px)',
                      backgroundColor: 'var(--ggui-color-surfaceVariant, #f5f5f5)',
                      borderRadius: 'var(--ggui-radius-md, 8px)',
                      textAlign: 'center',
                      border: '1px solid var(--ggui-color-outline, #e0e0e0)',
                    }}
                  >
                    <Text
                      variant="label"
                      size="sm"
                      style={{
                        color: 'var(--ggui-color-onSurfaceVariant, #666666)',
                        fontWeight: 500,
                      }}
                    >
                      {dayLabel}
                    </Text>
                    <Text
                      style={{
                        fontSize: '1.5rem',
                        lineHeight: '1',
                      }}
                    >
                      {item.icon || getWeatherEmoji('clear')}
                    </Text>
                    <Stack
                      direction="horizontal"
                      gap="var(--ggui-space-xs, 4px)"
                      style={{
                        justifyContent: 'center',
                      }}
                    >
                      <Text
                        variant="body"
                        size="sm"
                        style={{
                          color: 'var(--ggui-color-onSurface, #000000)',
                          fontWeight: 600,
                        }}
                      >
                        {item.high || '--'}°
                      </Text>
                      <Text
                        variant="body"
                        size="sm"
                        style={{
                          color: 'var(--ggui-color-onSurfaceVariant, #666666)',
                        }}
                      >
                        {item.low || '--'}°
                      </Text>
                    </Stack>
                  </Stack>
                );
              })
            ) : (
              <Text
                variant="body"
                size="sm"
                style={{
                  color: 'var(--ggui-color-onSurfaceVariant, #666666)',
                  padding: 'var(--ggui-space-md, 16px)',
                }}
              >
                No forecast data available
              </Text>
            )}
          </Stack>
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useMemo } from 'react';
import { Card, Stack, Text, Button } from '@ggui-ai/design/primitives';

interface Props {
  /** Array of elements with atomicNumber, symbol, name, atomicWeight, category (kebab-case), electronConfiguration, row, col */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    electronConfiguration?: string;
    row?: number;
    col?: number;
  }>;
}

// Map category to design system color tokens
const getCategoryColor = (category?: string): string => {
  const colorMap: Record<string, string> = {
    'alkali-metal': 'var(--ggui-color-primary-100, #e3f2fd)',
    'alkaline-earth': 'var(--ggui-color-primary-50, #f3e5f5)',
    'transition-metal': 'var(--ggui-color-secondary-100, #f3e5f5)',
    'post-transition-metal': 'var(--ggui-color-secondary-50, #fce4ec)',
    'metalloid': 'var(--ggui-color-tertiary-100, #fff3e0)',
    'nonmetal': 'var(--ggui-color-error-50, #ffebee)',
    'halogen': 'var(--ggui-color-warning-100, #fff8e1)',
    'noble-gas': 'var(--ggui-color-success-50, #e8f5e9)',
    'lanthanide': 'var(--ggui-color-info-100, #e0f2f1)',
    'actinide': 'var(--ggui-color-error-100, #ffcdd2)',
  };
  return colorMap[category || ''] || 'var(--ggui-color-surface, #ffffff)';
};

export default function PeriodicTable(props: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<(typeof props.elements)[0] | null>(null);

  // Filter elements based on search query
  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) {
      return props.elements;
    }
    const query = searchQuery.toLowerCase();
    return props.elements.filter(
      (el) =>
        el.name?.toLowerCase().includes(query) ||
        el.symbol?.toLowerCase().includes(query)
    );
  }, [searchQuery, props.elements]);

  // Get unique categories for legend
  const categories = useMemo(() => {
    const cats = new Set(props.elements.map((el) => el.category).filter(Boolean));
    return Array.from(cats).sort();
  }, [props.elements]);

  const handleSearchChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setSearchQuery(e.currentTarget.value);
  };

  return (
    <Stack direction="column" spacing="lg" css={{ padding: 'var(--ggui-spacing-lg)' }}>
      {/* Search Input */}
      <Stack direction="column" spacing="sm">
        <Text as="label" htmlFor="element-search" size="sm" css={{ fontWeight: '600', color: 'var(--ggui-color-onSurface)' }}>
          Search Elements
        </Text>
        <input
          id="element-search"
          type="text"
          placeholder="Search by element name or symbol..."
          value={searchQuery}
          onChange={handleSearchChange}
          style={{
            padding: 'var(--ggui-spacing-sm)',
            borderRadius: 'var(--ggui-radius-md)',
            border: '1px solid var(--ggui-color-outline)',
            backgroundColor: 'var(--ggui-color-surface)',
            color: 'var(--ggui-color-onSurface)',
            fontSize: '14px',
          }}
        />
      </Stack>

      {/* Legend */}
      <Stack direction="row" spacing="md" css={{ flexWrap: 'wrap' }}>
        {categories.map((category) => (
          <Stack key={category} direction="row" spacing="sm" css={{ alignItems: 'center' }}>
            <div
              css={{
                width: 'var(--ggui-spacing-sm, 16px)',
                height: 'var(--ggui-spacing-sm, 16px)',
                backgroundColor: getCategoryColor(category),
                border: '1px solid var(--ggui-color-outline, #ccc)',
                borderRadius: 'var(--ggui-radius-sm, 2px)',
              }}
            />
            <Text size="sm" css={{ color: 'var(--ggui-color-onSurface, #000)' }}>
              {category}
            </Text>
          </Stack>
        ))}
      </Stack>

      {/* Periodic Table Grid */}
      <div
        css={{
          display: 'grid',
          gridTemplateColumns: 'repeat(18, 1fr)',
          gap: 'var(--ggui-spacing-sm, 8px)',
          backgroundColor: 'var(--ggui-color-background, #fafafa)',
          padding: 'var(--ggui-spacing-md)',
          borderRadius: 'var(--ggui-radius-md, 4px)',
          border: '1px solid var(--ggui-color-outline, #ccc)',
          minHeight: '600px',
        }}
      >
        {filteredElements.map((element) => {
          const elementKey = element.atomicNumber ? String(element.atomicNumber) : element.symbol || '';

          return (
            <div
              key={elementKey}
              role="button"
              tabIndex={0}
              aria-label="Element card"
              css={{
                gridRow: element.row,
                gridColumn: element.col,
                backgroundColor: getCategoryColor(element.category),
                border: selectedElement?.atomicNumber === element.atomicNumber 
                  ? '2px solid var(--ggui-color-primary, #1976d2)'
                  : '1px solid var(--ggui-color-outline, #ccc)',
                borderRadius: 'var(--ggui-radius-md, 4px)',
                padding: 'var(--ggui-spacing-sm)',
                cursor: 'pointer',
                display: 'flex',
                flexDirection: 'column',
                justifyContent: 'center',
                alignItems: 'center',
                minHeight: '60px',
                position: 'relative',
                transition: 'all 0.2s ease-in-out',
                boxShadow: 'var(--ggui-shadow-sm, 0 1px 2px var(--ggui-color-onSurface, rgba(0, 0, 0, 0.12)))',
                '&:hover': {
                  boxShadow: 'var(--ggui-shadow-md, 0 2px 8px var(--ggui-color-onSurface, rgba(0, 0, 0, 0.12)))',
                  transform: 'translateY(calc(-1 * var(--ggui-spacing-xs, 2px)))',
                },
                '&:focus-visible': {
                  outline: '2px solid var(--ggui-color-primary, #1976d2)',
                  outlineOffset: '2px',
                },
              }}
              onClick={() => setSelectedElement(element)}
              onKeyDown={(e) => {
                if (e.key === 'Enter' || e.key === ' ') {
                  e.preventDefault();
                  setSelectedElement(element);
                }
              }}
            >
              {/* Atomic Number (top-left) */}
              <Text
                size="xs"
                css={{
                  position: 'absolute',
                  top: 'var(--ggui-spacing-xs, 4px)',
                  left: 'var(--ggui-spacing-xs, 4px)',
                  color: 'var(--ggui-color-onSurface, #000)',
                  fontWeight: '600',
                }}
              >
                {element.atomicNumber}
              </Text>

              {/* Symbol (large, centered) */}
              <Text
                size="lg"
                css={{
                  color: 'var(--ggui-color-onSurface, #000)',
                  fontWeight: '700',
                  textAlign: 'center',
                }}
              >
                {element.symbol}
              </Text>
            </div>
          );
        })}
      </div>

      {/* Detail Panel */}
      {selectedElement && (
        <Card variant="outlined" css={{ padding: 'var(--ggui-spacing-lg)' }}>
          <Stack direction="column" spacing="md">
            <Stack direction="row" spacing="md" css={{ alignItems: 'baseline' }}>
              <Text size="xl" css={{ fontWeight: '700', color: 'var(--ggui-color-onSurface, #000)' }}>
                {selectedElement.name}
              </Text>
              <Text size="md" css={{ color: 'var(--ggui-color-outline, #999)' }}>
                ({selectedElement.symbol})
              </Text>
            </Stack>

            <Stack direction="row" spacing="lg" css={{ flexWrap: 'wrap' }}>
              <Stack direction="column" spacing="xs">
                <Text size="sm" css={{ color: 'var(--ggui-color-outline, #999)' }}>
                  Atomic Number
                </Text>
                <Text size="md" css={{ fontWeight: '600', color: 'var(--ggui-color-onSurface, #000)' }}>
                  {selectedElement.atomicNumber}
                </Text>
              </Stack>

              <Stack direction="column" spacing="xs">
                <Text size="sm" css={{ color: 'var(--ggui-color-outline, #999)' }}>
                  Atomic Weight
                </Text>
                <Text size="md" css={{ fontWeight: '600', color: 'var(--ggui-color-onSurface, #000)' }}>
                  {selectedElement.atomicWeight?.toFixed(2)}
                </Text>
              </Stack>

              <Stack direction="column" spacing="xs">
                <Text size="sm" css={{ color: 'var(--ggui-color-outline, #999)' }}>
                  Category
                </Text>
                <Stack direction="row" spacing="sm" css={{ alignItems: 'center' }}>
                  <div
                    css={{
                      width: 'var(--ggui-spacing-md, 20px)',
                      height: 'var(--ggui-spacing-md, 20px)',
                      backgroundColor: getCategoryColor(selectedElement.category),
                      border: '1px solid var(--ggui-color-outline, #ccc)',
                      borderRadius: 'var(--ggui-radius-sm, 2px)',
                    }}
                  />
                  <Text size="md" css={{ fontWeight: '600', color: 'var(--ggui-color-onSurface, #000)' }}>
                    {selectedElement.category}
                  </Text>
                </Stack>
              </Stack>
            </Stack>

            <Stack direction="column" spacing="xs">
              <Text size="sm" css={{ color: 'var(--ggui-color-outline, #999)' }}>
                Electron Configuration
              </Text>
              <Text
                size="md"
                css={{
                  fontWeight: '600',
                  color: 'var(--ggui-color-onSurface, #000)',
                  fontFamily: 'monospace',
                  wordBreak: 'break-word',
                }}
              >
                {selectedElement.electronConfiguration}
              </Text>
            </Stack>

            <Button
              variant="outlined"
              onClick={() => setSelectedElement(null)}
              css={{ alignSelf: 'flex-start' }}
            >
              Close
            </Button>
          </Stack>
        </Card>
      )}
    </Stack>
  );
}

import React from "react";
import { Card, Stack, Text } from "@ggui-ai/design/primitives";

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

const CONDITION_ICONS: Record<string, string> = {
  sunny: "☀️",
  clear: "☀️",
  cloudy: "☁️",
  "partly cloudy": "⛅",
  overcast: "🌥️",
  rainy: "🌧️",
  rain: "🌧️",
  drizzle: "🌦️",
  stormy: "⛈️",
  storm: "⛈️",
  thunderstorm: "🌩️",
  snowy: "❄️",
  snow: "❄️",
  windy: "💨",
  foggy: "🌫️",
  fog: "🌫️",
  hazy: "🌁",
  hail: "🌨️",
  tornado: "🌪️",
};

function getConditionIcon(condition: string): string {
  const key = condition.toLowerCase().trim();
  return CONDITION_ICONS[key] ?? "🌡️";
}

export default function GeneratedComponent(props: Props) {
  const {
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
    unit = "C",
    forecast,
  } = props;

  const conditionIcon = getConditionIcon(condition);

  return (
    <div
      style={{
        minWidth: "320px",
        maxWidth: "480px",
        width: "100%",
        margin: "0 auto",
        fontFamily: "var(--ggui-font-family, sans-serif)",
      }}
    >
      <Card variant="elevated" aria-label={"Weather for " + city}>
        <Stack direction="vertical" gap="lg">

          {/* ── Header: city + condition icon ── */}
          <Stack direction="horizontal" gap="sm" style={{ justifyContent: "space-between", alignItems: "flex-start" }}>
            <Stack direction="vertical" gap="xs">
              <Text variant="overline" style={{ color: "var(--ggui-color-onSurface, #6b7280)", letterSpacing: "0.08em", textTransform: "uppercase", fontSize: "0.75rem" }}>
                Current Weather
              </Text>
              <Text variant="heading" size="lg" style={{ color: "var(--ggui-color-onSurface, #111827)", fontWeight: 700 }}>
                {city}
              </Text>
            </Stack>
            <span
              role="img"
              aria-label={condition}
              style={{ fontSize: "3rem", lineHeight: 1 }}
            >
              {conditionIcon}
            </span>
          </Stack>

          {/* ── Temperature + condition ── */}
          <Stack direction="vertical" gap="xs" style={{ alignItems: "flex-start" }}>
            <Stack direction="horizontal" gap="xs" style={{ alignItems: "flex-end" }}>
              <Text
                variant="display"
                style={{
                  fontSize: "5rem",
                  fontWeight: 800,
                  lineHeight: 1,
                  color: "var(--ggui-color-primary, #2563eb)",
                  letterSpacing: "-0.04em",
                }}
              >
                {temperature}
              </Text>
              <Text
                variant="heading"
                style={{
                  fontSize: "2rem",
                  fontWeight: 600,
                  color: "var(--ggui-color-primary, #2563eb)",
                  paddingBottom: "0.6rem",
                }}
              >
                {"°" + unit}
              </Text>
            </Stack>
            <Text
              variant="body"
              size="md"
              style={{
                color: "var(--ggui-color-onSurface, #374151)",
                fontWeight: 500,
              }}
            >
              {condition}
            </Text>
          </Stack>

          {/* ── Stats row: humidity + wind ── */}
          <div
            style={{
              display: "grid",
              gridTemplateColumns: "1fr 1fr",
              gap: "var(--ggui-spacing-md, 1rem)",
            }}
          >
            {/* Humidity */}
            <Card
              variant="outlined"
              aria-label={"Humidity " + humidity + " percent"}
              style={{ padding: "var(--ggui-spacing-sm, 0.75rem)" }}
            >
              <Stack direction="vertical" gap="xs" style={{ alignItems: "center" }}>
                <span role="img" aria-hidden="true" style={{ fontSize: "1.5rem" }}>💧</span>
                <Text
                  variant="heading"
                  size="sm"
                  style={{ color: "var(--ggui-color-onSurface, #111827)", fontWeight: 700 }}
                >
                  {humidity + "%"}
                </Text>
                <Text
                  variant="caption"
                  style={{ color: "var(--ggui-color-onSurface, #6b7280)", fontSize: "0.75rem" }}
                >
                  Humidity
                </Text>
              </Stack>
            </Card>

            {/* Wind */}
            <Card
              variant="outlined"
              aria-label={"Wind speed " + windSpeed + " km/h"}
              style={{ padding: "var(--ggui-spacing-sm, 0.75rem)" }}
            >
              <Stack direction="vertical" gap="xs" style={{ alignItems: "center" }}>
                <span role="img" aria-hidden="true" style={{ fontSize: "1.5rem" }}>💨</span>
                <Text
                  variant="heading"
                  size="sm"
                  style={{ color: "var(--ggui-color-onSurface, #111827)", fontWeight: 700 }}
                >
                  {windSpeed + " km/h"}
                </Text>
                <Text
                  variant="caption"
                  style={{ color: "var(--ggui-color-onSurface, #6b7280)", fontSize: "0.75rem" }}
                >
                  Wind Speed
                </Text>
              </Stack>
            </Card>
          </div>

          {/* ── Divider ── */}
          <hr
            style={{
              border: "none",
              borderTop: "1px solid var(--ggui-color-outline, #e5e7eb)",
              margin: 0,
            }}
          />

          {/* ── 5-day forecast strip ── */}
          <Stack direction="vertical" gap="sm">
            <Text
              variant="overline"
              style={{
                color: "var(--ggui-color-onSurface, #6b7280)",
                letterSpacing: "0.08em",
                textTransform: "uppercase",
                fontSize: "0.75rem",
              }}
            >
              5-Day Forecast
            </Text>
            <div
              role="list"
              aria-label="5-day forecast"
              style={{
                display: "grid",
                gridTemplateColumns: "repeat(5, 1fr)",
                gap: "var(--ggui-spacing-xs, 0.5rem)",
              }}
            >
              {forecast.slice(0, 5).map((item, index) => (
                <div
                  key={item.day ?? index}
                  role="listitem"
                  aria-label={(item.day ?? "Day") + ": high " + (item.high ?? "—") + "° " + unit + ", low " + (item.low ?? "—") + "° " + unit}
                  style={{
                    display: "flex",
                    flexDirection: "column",
                    alignItems: "center",
                    gap: "var(--ggui-spacing-xs, 0.4rem)",
                    padding: "var(--ggui-spacing-sm, 0.5rem) var(--ggui-spacing-xs, 0.25rem)",
                    borderRadius: "var(--ggui-radius-md, 8px)",
                    background: "var(--ggui-color-surfaceVariant, rgba(0,0,0,0.03))",
                    transition: "background 0.15s ease",
                  }}
                >
                  <Text
                    variant="caption"
                    style={{
                      color: "var(--ggui-color-onSurface, #6b7280)",
                      fontSize: "0.7rem",
                      fontWeight: 600,
                      textTransform: "uppercase",
                      letterSpacing: "0.05em",
                    }}
                  >
                    {item.day ?? "—"}
                  </Text>
                  <span
                    role="img"
                    aria-label={item.icon ?? "weather"}
                    style={{ fontSize: "1.4rem", lineHeight: 1 }}
                  >
                    {item.icon ?? "🌡️"}
                  </span>
                  <Text
                    variant="body"
                    size="sm"
                    style={{
                      color: "var(--ggui-color-onSurface, #111827)",
                      fontWeight: 700,
                      fontSize: "0.8rem",
                    }}
                  >
                    {(item.high ?? "—") + "°"}
                  </Text>
                  <Text
                    variant="caption"
                    style={{
                      color: "var(--ggui-color-onSurface, #9ca3af)",
                      fontSize: "0.75rem",
