import React, { useState, useEffect, useCallback } from "react";
import { Card, Stack, Text } from "@ggui-ai/design/primitives";

interface StockItem {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface PriceUpdatePayload {
  type: string;
  symbol: string;
  price: number;
  change: number;
  changePercent: number;
}

interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
}

function formatPrice(price?: number): string {
  if (price == null) return "—";
  return price.toLocaleString("en-US", { style: "currency", currency: "USD", minimumFractionDigits: 2 });
}

function formatChange(change?: number): string {
  if (change == null) return "—";
  const abs = Math.abs(change).toFixed(2);
  return change >= 0 ? "+".concat(abs) : "-".concat(abs);
}

function formatPercent(pct?: number): string {
  if (pct == null) return "—";
  const abs = Math.abs(pct).toFixed(2).concat("%");
  return pct >= 0 ? "+".concat(abs) : "-".concat(abs);
}

function formatTime(date: Date): string {
  return date.toLocaleTimeString("en-US", { hour: "2-digit", minute: "2-digit", second: "2-digit" });
}

interface StockCardProps {
  stock: StockItem;
  isUpdated: boolean;
}

function StockCard({ stock, isUpdated }: StockCardProps) {
  const changeVal = stock.change ?? 0;
  const isPositive = changeVal > 0;
  const isNegative = changeVal < 0;
  const isZero = !isPositive && !isNegative;

  const changeColor = isZero
    ? "var(--ggui-color-onSurface)"
    : isPositive
    ? "var(--ggui-color-positive, #16a34a)"
    : "var(--ggui-color-negative, #dc2626)";

  const changeBg = isZero
    ? "var(--ggui-color-surfaceVariant, var(--ggui-color-surface))"
    : isPositive
    ? "var(--ggui-color-positiveContainer, var(--ggui-color-surface))"
    : "var(--ggui-color-negativeContainer, var(--ggui-color-surface))";

  const arrow = isZero ? "▸" : isPositive ? "▲" : "▼";

  return (
    <div
      role="article"
      aria-label={[stock.symbol ?? "Unknown", "stock card"].join(" ")}
      style={{
        borderRadius: "var(--ggui-radius-md, 12px)",
        outline: isUpdated ? "2px solid var(--ggui-color-primary, #2563eb)" : "none",
        outlineOffset: "2px",
        animation: isUpdated ? "cardPulse 0.6s ease-out" : "none",
        transition: "transform 0.2s ease, box-shadow 0.2s ease",
      }}
    >
      <Card variant="elevated" style={{ height: "100%", padding: "var(--ggui-spacing-5, 1.25rem)" }}>
        <Stack direction="column" gap={3}>
          <Stack direction="row" justify="between" align="center">
            <Text
              as="span"
              size="xl"
              weight="bold"
              style={{ letterSpacing: "0.05em", color: "var(--ggui-color-primary, #2563eb)" }}
            >
              {stock.symbol ?? "—"}
            </Text>
            {isUpdated && (
              <span
                aria-label="Live update received"
                role="status"
                style={{
                  display: "inline-block",
                  width: "var(--ggui-spacing-2, 0.5rem)",
                  height: "var(--ggui-spacing-2, 0.5rem)",
                  borderRadius: "var(--ggui-radius-full, 9999px)",
                  background: "var(--ggui-color-primary, #2563eb)",
                  animation: "livePulse 1s ease-in-out infinite",
                }}
              />
            )}
          </Stack>

          <Text
            as="p"
            size="sm"
            style={{
              color: "var(--ggui-color-onSurfaceVariant, var(--ggui-color-onSurface))",
              whiteSpace: "nowrap",
              overflow: "hidden",
              textOverflow: "ellipsis",
            }}
          >
            {stock.name ?? "Unknown Company"}
          </Text>

          <Text as="p" size="2xl" weight="bold" style={{ color: "var(--ggui-color-onSurface)", lineHeight: 1.1 }}>
            {formatPrice(stock.price)}
          </Text>

          <Stack direction="row" gap={2} align="center">
            <span
              aria-label={"Price change: ".concat(formatChange(stock.change))}
              style={{
                display: "inline-flex",
                alignItems: "center",
                gap: "var(--ggui-spacing-1, 0.25rem)",
                padding: "var(--ggui-spacing-1, 0.25rem) var(--ggui-spacing-2, 0.5rem)",
                borderRadius: "var(--ggui-radius-full, 9999px)",
                background: changeBg,
                color: changeColor,
                fontSize: "var(--ggui-font-size-sm, 0.875rem)",
                fontWeight: 600,
                border: "1px solid var(--ggui-color-outline)",
              }}
            >
              {arrow}
              {" "}
              {formatChange(stock.change)}
            </span>
            <span
              aria-label={"Change percent: ".concat(formatPercent(stock.changePercent))}
              style={{
                display: "inline-flex",
                alignItems: "center",
                padding: "var(--ggui-spacing-1, 0.25rem) var(--ggui-spacing-2, 0.5rem)",
                borderRadius: "var(--ggui-radius-full, 9999px)",
                background: changeBg,
                color: changeColor,
                fontSize: "var(--ggui-font-size-sm, 0.875rem)",
                fontWeight: 600,
                border: "1px solid var(--ggui-color-outline)",
              }}
            >
              {formatPercent(stock.changePercent)}
            </span>
          </Stack>
        </Stack>
      </Card>
    </div>
  );
}

export default function GeneratedComponent({ stocks: initialStocks }: Props) {
  const [stockData, setStockData] = useState<StockItem[]>(initialStocks ?? []);
  const [updatedSymbols, setUpdatedSymbols] = useState<Set<string>>(new Set());
  const [currentTime, setCurrentTime] = useState<Date>(new Date());
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
  const [connectionStatus, setConnectionStatus] = useState<"connecting" | "live" | "idle">("connecting");

  useEffect(() => {
    setStockData(initialStocks ?? []);
  }, [initialStocks]);

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    const t = setTimeout(() => {
      setConnectionStatus((s) => (s === "connecting" ? "idle" : s));
    }, 3000);
    return () => clearTimeout(t);
  }, []);

  const handleAgentData = useCallback((event: Event) => {
    const customEvent = event as CustomEvent<PriceUpdatePayload>;
    const detail = customEvent.detail;
    if (!detail || detail.type !== "price-update") return;

    const sym = detail.symbol;
    const price = detail.price;
    const change = detail.change;
    const changePercent = detail.changePercent;

    setStockData((prev) =>
      prev.map((s) => (s.symbol === sym ? { ...s, price, change, changePercent } : s))
    );

    setUpdatedSymbols((prev) => {
      const next = new Set(prev);
      next.add(sym);
      return next;
    });
    setLastUpdated(new Date());
    setConnectionStatus("live");

    setTimeout(() => {
      setUpdatedSymbols((prev) => {
        const next = new Set(prev);
        next.delete(sym);
        return next;
      });
    }, 2500);
  }, []);

  useEffect(() => {
    const el = globalThis.addEventListener
      ? globalThis
      : null;
    if (!el) return;
    el.addEventListener("ggui:agent-data", handleAgentData);
    return () => el.removeEventListener("ggui:agent-data", handleAgentData);
  }, [handleAgentData]);

  const statusLabel =
    connectionStatus === "connecting"
      ? "Connecting…"
      : connectionStatus === "live"
      ? "Live"
      : "Waiting for data";

  const statusColor =
    connectionStatus === "connecting"
      ? "var(--ggui-color-warning, #d97706)"
      : connectionStatus === "live"
      ? "var(--ggui-color-positive, #16a34a)"
      : "var(--ggui-color-onSurfaceVariant, var(--ggui-color-onSurface))";

  const securityWord = stockData.length === 1 ? "security" : "securities";

  return (
    <>
      <style>{`
        @keyframes livePulse {
          0%, 100% { opacity: 1; transform: scale(1); }
          50% { opacity: 0.4; transform: scale(1.4); }
        }
        @keyframes cardPulse {
          0%   { box-shadow: 0 0 0 0 var(--ggui-color-primary, #2563eb); }
          70%  { box-shadow: 0 0 0 var(--ggui-spacing-2, 8px) transparent; }
          100% { box-shadow: 0 0 0 0 transparent; }
        }
        .stock-grid {
          display: grid;
          grid-template-columns: repeat(4, 1fr);
          gap: var(--ggui-spacing-4, 1rem);
        }
        @media (max-width: 1024px) { .stock-grid { grid-template-columns: repeat(3, 1fr); } }
        @media (max-width: 768px)  { .stock-grid { grid-template-columns: repeat(2, 1fr); } }
        @media (max-width: 480px)  { .stock-grid { grid-template-columns: 1fr; } }
        .stock-card-wrapper:hover > div {
          transform: translateY(-3px);
          box-shadow: 0 var(--ggui-spacing-2, 0.5rem) var(--ggui-spacing-6, 1.5rem) var(--ggui-color-shadow, var(--ggui-color-outline));
        }
      `}</style>

      <Stack
        direction="column"
        gap={6}
        style={{
          padding: "var(--ggui-spacing-6, 1.5rem)",
          minHeight: "100vh",
          background: "var(--ggui-color-background, var(--ggui-color-surface))",
        }}
      >
        {/* Header */}
        <Card variant="outlined" style={{ padding: "var(--ggui-spacing-5, 1.25rem) var(--ggui-spacing-6, 1.5rem)" }}>
          <Stack direction="row" justify="between" align="center" wrap>
            <Stack direction="column" gap={1}>
              <Text as="h1" size="2xl" weight="bold" style={{ color: "var(--ggui-color-onSurface)" }}>
                📈 Market Watch
              </Text>
              <Stack direction="row" gap={2} align="center">
                <span
                  aria-label={"Feed status: ".concat(statusLabel)}
                  style={{
                    display: "inline-block",
                    width: "var(--ggui-spacing-2, 0.5rem)",
                    height: "var(--ggui-spacing-2, 0.5rem)",
                    borderRadius: "var(--ggui-radius-full, 9999px)",
                    background: statusColor,
                    animation: connectionStatus !== "idle" ? "livePulse 1.4s ease-in-out infinite" : "none",
                  }}
                />
                <Text as="span" size="sm" style={{ color: statusColor, fontWeight: 600 }}>
                  {statusLabel}
                </Text>
              </Stack>
            </Stack>

            <Stack direction="column" gap={1} align="end">
              <Text
                as="span"
                size="sm"
                style={{ color: "var(--ggui-color-onSurfaceVariant, var(--ggui-color-onSurface))" }}
              >
                Current Time
              </Text>
              <Text
                as="time"
                dateTime={currentTime.toISOString()}
                size="lg"
                weight="bold"
                style={{ color: "var(--ggui-color-onSurface)", fontVariantNumeric: "tabular-nums" }}
              >
                {formatTime(currentTime)}
              </Text>
            </Stack>
          </Stack>
        </Card>

        {/* Connecting splash */}
        {connectionStatus === "connecting" && stockData.length === 0 ? (
          <Stack
            direction="column"
            gap={4}
            align="center"
            justify="center"
            style={{ flex: 1, padding: "var(--ggui-spacing-12, 3rem)" }}
          >
            <span
              style={{ fontSize: "2.5rem", animation: "livePulse 1.5s ease-in-out infinite" }}
              role="img"
              aria-label="Satellite dish"
            >
              📡
            </span>
            <Text
              as="p"
              size="lg"
              style={{ color: "var(--ggui-color-onSurfaceVariant, var(--ggui-color-onSurface))" }}
            >
              Connecting to market data…
            </Text>
          </Stack>
        ) : (
          <main aria-label="Stock price grid">
            <div className="stock-grid" role="list">
              {stockData.map((stock, idx) => (
                <div
                  key={stock.symbol ?? String(idx)}
                  role="listitem"
                  className="stock-card-wrapper"
                >
                  <StockCard
                    stock={stock}
                    isUpdated={updatedSymbols.has(stock.symbol ?? "")}
                  />
                </div>
              ))}
            </div>
          </main>
        )}

        {/* Footer */}
        <Card variant="outlined" style={{ padding: "var(--ggui-spacing-4, 1rem) var(--ggui-spacing-6, 1.5rem)" }}>
          <Stack direction="row" justify="between" align="center" wrap gap={2}>
            <Text
              as="p"
              size="sm"
              style={{ color: "var(--ggui-color-onSurfaceVariant, var(--ggui-color-onSurface))" }}
            >
              {stockData.length} {securityWord} tracked
            </Text>
            <Stack direction="row" gap={2} align="center">
              <Text
                as="span"
                size="sm"
                style={{ color: "var(--ggui-color-onSurfaceVariant, var(--ggui-color-onSurface))" }}
              >
                Last Updated:
              </Text>
              {lastUpdated ? (
                <Text
                  as="time"
                  dateTime={lastUpdated.toISOString()}
                  size="sm"
                  weight="bold"
                  style={{ color: "var(--ggui-color-onSurface)", fontVariantNumeric: "tabular-nums" }}
                >
                  {formatTime(lastUpdated)}
                </Text>
              ) : (
