  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * WeatherCard Component
 * A reusable weather dashboard card showing current stats and a 5-day forecast.
 */
export default function WeatherCard({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = '°C',
  forecast = [],
}: Props) {

  // Helper to get emoji based on condition string if icon is not provided
  const getWeatherEmoji = (cond: string) => {
    const lower = (cond || '').toLowerCase();
    if (lower.includes('sun') || lower.includes('clear')) return '☀️';
    if (lower.includes('cloud')) return '☁️';
    if (lower.includes('rain') || lower.includes('drizzle')) return '🌧️';
    if (lower.includes('snow')) return '❄️';
    if (lower.includes('storm') || lower.includes('thunder')) return '⛈️';
    if (lower.includes('mist') || lower.includes('fog')) return '🌫️';
    return '⛅';
  };

  return (
    <Box padding="var(--ggui-spacing-4)">
      <Card 
        padding={24} 
        style={{ 
          maxWidth: '400px',
          backgroundColor: 'var(--ggui-color-surfaceVariant)',
