          {/* Current Reading */}
          <Row justify="between" align="center">
            <Text 
              weight="bold" 
              style={{ fontSize: 'var(--ggui-font-size-4xl)', color: 'var(--ggui-color-onSurface)' }}
            >
              {temperature}{unit}
            </Text>
            <span style={{ fontSize: 'var(--ggui-font-size-4xl)' }} role="img" aria-label={condition}>
              {getWeatherEmoji(condition)}
            </span>
          </Row>

          {/* Details Box */}
          <Box 
            padding="var(--ggui-spacing-4)" 
            style={{ 
              background: 'var(--ggui-color-surface)',
              borderRadius: 'var(--ggui-shape-radius-md)',
              border: '1px solid var(--ggui-color-outlineVariant)' 
            }}
          >
            <Row justify="around" align="center">
              <Stack align="center" gap={4}>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" weight="semibold">
                  HUMIDITY
                </Text>
                <Text variant="body" weight="bold" color="var(--ggui-color-onSurface)">
                  {humidity}%
                </Text>
              </Stack>
              <Divider orientation="vertical" />
              <Stack align="center" gap={4}>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" weight="semibold">
                  WIND
                </Text>
                <Text variant="body" weight="bold" color="var(--ggui-color-onSurface)">
                  {windSpeed} km/h
                </Text>
              </Stack>
            </Row>
          </Box>

          {/* Forecast Section */}
          {forecast && forecast.length > 0 && (
            <Stack direction="vertical" gap={12}>
              <Divider />
              <Text variant="label" weight="bold" color="var(--ggui-color-onSurfaceVariant)">
                5-DAY FORECAST
              </Text>
              <Row justify="between">
                {forecast.map((item, idx) => {
                  const dayKey = (item.day || 'day') + '-' + idx;
                  return (
                    <Stack key={dayKey} align="center" gap={6}>
                      <Text variant="caption" weight="medium" color="var(--ggui-color-onSurface)">
                        {item.day}
                      </Text>
                      <span role="img" aria-label="forecast condition" style={{ fontSize: 'var(--ggui-font-size-lg)' }}>
                        {item.icon || '⛅'}
                      </span>
                      <Stack direction="vertical" align="center" gap={0}>
                        <Text variant="caption" weight="bold" color="var(--ggui-color-onSurface)">
                          {item.high}°
                        </Text>
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                          {item.low}°
                        </Text>
                      </Stack>
                    </Stack>
                  );
                })}
              </Row>
            </Stack>
          )}
        </Stack>
      </Card>
    </Box>
  );
}

import React, { useState, useMemo } from 'react';
import { Stack, Card, Text, Input, Button } from '@ggui-ai/design/primitives';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  electronConfiguration?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Array of elements with atomicNumber, symbol, name, atomicWeight, category (kebab-case), electronConfiguration, row, col */
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; electronConfiguration?: string; row?: number; col?: number }>;
}

const CATEGORY_MAP: Record<string, { label: string; color: string }> = {
  'alkali-metal': { label: 'Alkali Metal', color: 'var(--ggui-color-primary-container)' },
  'alkaline-earth': { label: 'Alkaline Earth', color: 'var(--ggui-color-secondary-container)' },
  'transition-metal': { label: 'Transition Metal', color: 'var(--ggui-color-tertiary-container)' },
  'post-transition-metal': { label: 'Post-transition Metal', color: 'var(--ggui-color-info-container)' },
  'metalloid': { label: 'Metalloid', color: 'var(--ggui-color-warning-container)' },
  'nonmetal': { label: 'Nonmetal', color: 'var(--ggui-color-error-container)' },
  'halogen': { label: 'Halogen', color: 'var(--ggui-color-success-container)' },
  'noble-gas': { label: 'Noble Gas', color: 'var(--ggui-color-surface-variant)' },
  'lanthanide': { label: 'Lanthanide', color: 'var(--ggui-color-primary-fixed-dim)' },
  'actinide': { label: 'Actinide', color: 'var(--ggui-color-secondary-fixed-dim)' },
};

export default function PeriodicTable({ elements = [] }: Props) {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedNum, setSelectedNum] = useState<number | null>(null);

  const selected = useMemo(() => elements.find(e => e.atomicNumber === selectedNum) || null, [elements, selectedNum]);

  const isHighlighted = (el: ElementData) => {
    if (!searchTerm.trim()) return true;
    const term = searchTerm.toLowerCase();
    return (el.name?.toLowerCase().includes(term) || el.symbol?.toLowerCase().includes(term)) ?? false;
  };

  return (
    <Stack gap="xl" padding="xl" style={{ width: '100%', minWidth: 'fit-content' }}>
      <Stack direction="row" align="center" justify="space-between" wrap="wrap" gap="md">
        <Stack gap="none">
          <Text variant="headline-medium">Periodic Table</Text>
          <Text variant="body-medium" color="onSurfaceVariant">Interactive chemical database</Text>
        </Stack>
        <Stack gap="xs">
          <Text as="label" htmlFor="search-id" variant="label-medium">Search</Text>
          <Input label="Search" id="search-id" placeholder="Find element..." value={searchTerm} onChange={setSearchTerm} style={{ width: '280px' }} />
        </Stack>
      </Stack>

      <Stack direction="row" gap="md" wrap="wrap" justify="center">
        {Object.entries(CATEGORY_MAP).map(([key, cat]) => (
          <Stack key={key} direction="row" gap="xs" align="center">
            <div style={{ width: 'var(--ggui-spacing-md)', height: 'var(--ggui-spacing-md)', borderRadius: 'var(--ggui-radius-xs)', backgroundColor: cat.color, border: '1px solid var(--ggui-color-outline-variant)' }} />
            <Text variant="label-medium">{cat.label}</Text>
          </Stack>
        ))}
      </Stack>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(18, minmax(64px, 1fr))', gap: 'var(--ggui-spacing-xs)', padding: 'var(--ggui-spacing-md)', backgroundColor: 'var(--ggui-color-surface-container-low)', borderRadius: 'var(--ggui-radius-lg)', overflowX: 'auto' }}>
        {elements.map((el) => {
          const cat = CATEGORY_MAP[el.category || ''] || { color: 'var(--ggui-color-surface-container)' };
          const active = isHighlighted(el);
          const sel = selectedNum === el.atomicNumber;
          return (
            <div key={el.atomicNumber} style={{ gridColumn: el.col, gridRow: el.row, opacity: active ? 1 : 0.2, transition: 'opacity 0.2s', transform: sel ? 'scale(1.1)' : 'scale(1)', zIndex: sel ? 5 : 1 }}>
              <Card variant={sel ? 'filled' : 'outlined'} onClick={() => setSelectedNum(el.atomicNumber ?? null)} style={{ height: '80px', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', position: 'relative', backgroundColor: cat.color, cursor: 'pointer', borderColor: sel ? 'var(--ggui-color-primary)' : 'var(--ggui-color-outline-variant)', padding: 'var(--ggui-spacing-xs)' }}>
                <div style={{ position: 'absolute', top: '4px', left: '6px' }}><Text variant="label-small" style={{ fontSize: '10px' }}>{el.atomicNumber}</Text></div>
                <Text variant="title-large" style={{ fontWeight: 800 }}>{el.symbol}</Text>
                <Text variant="label-small" style={{ fontSize: '9px', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis', maxWidth: '100%' }}>{el.name}</Text>
              </Card>
            </div>
          );
        })}
      </div>

      {selected && (
        <Card variant="elevated" padding="xl">
          <Stack direction="row" gap="xl" wrap="wrap" align="start">
            <Stack align="center" justify="center" style={{ width: '120px', height: '120px', borderRadius: 'var(--ggui-radius-lg)', backgroundColor: CATEGORY_MAP[selected.category || '']?.color || 'var(--ggui-color-surface-container)', border: '1px solid var(--ggui-color-outline)', flexShrink: 0 }}>
              <Text variant="headline-large" style={{ fontWeight: 900 }}>{selected.symbol}</Text>
              <Text variant="title-small">{selected.atomicNumber}</Text>
            </Stack>
            <Stack gap="lg" style={{ flex: 1, minWidth: '300px' }}>
              <Stack direction="row" align="baseline" gap="md">
                <Text variant="headline-medium">{selected.name}</Text>
                <Text variant="title-large" color="onSurfaceVariant">{selected.atomicWeight} u</Text>
              </Stack>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 'var(--ggui-spacing-lg)' }}>
                <Stack gap="none"><Text variant="label-large" color="onSurfaceVariant">Classification</Text><Text variant="body-large" style={{ textTransform: 'capitalize' }}>{selected.category?.replace(/-/g, ' ')}</Text></Stack>
                <Stack gap="none"><Text variant="label-large" color="onSurfaceVariant">Electron Config</Text><Text variant="body-large" style={{ fontFamily: 'monospace' }}>{selected.electronConfiguration}</Text></Stack>
              </div>
            </Stack>
            <Button variant="outlined" size="sm" onClick={() => setSelectedNum(null)}>Close</Button>
          </Stack>
        </Card>
      )}
    </Stack>
  );
}

import React, { useState, useEffect } from 'react';
import { Card, Stack, Text } from '@ggui-ai/design/primitives';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Stock[];
}

/**
 * Stock Ticker Dashboard component
 * Displays live stock prices with real-time updates via ggui:agent-data.
 */
export default function StockDashboard({ stocks = [] }: Props) {
  const [localStocks, setLocalStocks] = useState<Stock[]>(stocks);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);

  // Sync initial props
  useEffect(() => {
    if (stocks && stocks.length > 0) {
      setLocalStocks(stocks);
    }
  }, [stocks]);

  // Live clock
  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  // Listen for agent data updates
  useEffect(() => {
    const handleAgentData = (event: any) => {
      const detail = event.detail || {};
      const { type, data } = detail;

      if (type === 'price-update' && data?.symbol) {
        setLocalStocks((prev) =>
          prev.map((s) => {
            if (s.symbol === data.symbol) {
              return {
                ...s,
                price: typeof data.price === 'number' ? data.price : s.price,
                change: typeof data.change === 'number' ? data.change : s.change,
                changePercent: typeof data.changePercent === 'number' ? data.changePercent : s.changePercent,
              };
            }
            return s;
          })
        );
        setLastUpdated(new Date());
      }
    };

    // Listening for the agent data event as specified in the Stream Contract.
    // We use the global addEventListener directly.
    try {
      addEventListener('ggui:agent-data', handleAgentData as EventListener);
      return () => removeEventListener('ggui:agent-data', handleAgentData as EventListener);
    } catch (e) {
      // Fallback or silent fail if environment restricts global event listeners
    }
  }, []);

  const formatPrice = (val?: number) => {
    if (val === undefined) return '—';
    return '$' + val.toFixed(2);
  };

  const formatPercent = (val?: number) => {
    if (val === undefined) return '0.00%';
    const sign = val > 0 ? '+' : '';
    return sign + val.toFixed(2) + '%';
  };

  const formatChange = (val?: number) => {
    if (val === undefined) return '0.00';
    const sign = val > 0 ? '+' : '';
    return sign + val.toFixed(2);
  };

  return (
    <Stack gap="xl" padding="xl" style={{ width: '100%', minHeight: '100%', backgroundColor: 'var(--ggui-color-surface)' }}>
      {/* Header Section */}
      <Stack direction="row" justify="space-between" align="center" style={{ flexWrap: 'wrap', gap: 'var(--ggui-spacing-md)' }}>
        <Stack gap="xs">
          <Text variant="h2" weight="black" style={{ color: 'var(--ggui-color-onSurface)' }}>
            Market Watch
          </Text>
          <Text variant="body2" style={{ color: 'var(--ggui-color-onSurfaceVariant)' }}>
            Live exchange data • {currentTime.toLocaleDateString(undefined, { weekday: 'long', month: 'short', day: 'numeric' })}
          </Text>
        </Stack>

        <Card variant="filled" padding="sm" style={{ backgroundColor: 'var(--ggui-color-surfaceVariant)', minWidth: '120px' }}>
          <Stack align="center" gap="none">
            <Text variant="body1" weight="bold">
              {currentTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' })}
            </Text>
            <Text variant="caption">EST</Text>
          </Stack>
        </Card>
      </Stack>

      {/* Grid Layout Container */}
      <div
        style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
          gap: 'var(--ggui-spacing-lg)',
          width: '100%',
        }}
      >
        {localStocks.map((stock) => {
          const isPositive = (stock.change ?? 0) >= 0;
          const statusColor = isPositive 
            ? 'var(--ggui-color-success)' 
            : 'var(--ggui-color-error)';
          const bgColor = isPositive 
            ? 'var(--ggui-color-successContainer)' 
            : 'var(--ggui-color-errorContainer)';

          return (
            <Card 
              key={stock.symbol} 
              padding="lg" 
              variant="elevated" 
              style={{ 
                borderTop: '4px solid ' + statusColor
              }}
            >
              <Stack gap="lg">
                <Stack direction="row" justify="space-between" align="flex-start">
                  <Stack gap="xs">
                    <Text variant="h3" weight="black" style={{ fontSize: '1.5rem', lineHeight: 1 }}>
                      {stock.symbol}
                    </Text>
                    <Text variant="caption" style={{ color: 'var(--ggui-color-onSurfaceVariant)', fontWeight: 500 }}>
                      {stock.name}
                    </Text>
                  </Stack>
                  <Text variant="h3" weight="bold" style={{ color: 'var(--ggui-color-onSurface)' }}>
                    {formatPrice(stock.price)}
                  </Text>
                </Stack>

                <Stack direction="row" gap="md" align="center">
                  <div
                    style={{
                      padding: 'var(--ggui-spacing-xs) var(--ggui-spacing-sm)',
                      borderRadius: 'var(--ggui-radius-sm)',
                      backgroundColor: bgColor,
                      color: statusColor,
                    }}
                  >
                    <Text variant="body2" weight="bold">
                      {formatPercent(stock.changePercent)}
                    </Text>
                  </div>
                  <Text variant="body1" weight="bold" style={{ color: statusColor }}>
                    {formatChange(stock.change)}
                  </Text>
                </Stack>
              </Stack>
            </Card>
          );
        })}

        {localStocks.length === 0 && (
          <Card padding="xl" variant="outlined" style={{ gridColumn: '1 / -1', textAlign: 'center' }}>
            <Text variant="body1" style={{ color: 'var(--ggui-color-onSurfaceVariant)' }}>No stock data available.</Text>
          </Card>
        )}
      </div>

      {/* Footer Info */}
      <Stack align="center" padding="md" style={{ borderTop: '1px solid var(--ggui-color-outlineVariant)', marginTop: 'var(--ggui-spacing-xl)' }}>
        <Stack direction="row" gap="xs" align="center">
          <div 
            style={{ 
              width: '8px', 
              height: '8px', 
              borderRadius: '50%', 
              backgroundColor: lastUpdated ? 'var(--ggui-color-success)' : 'var(--ggui-color-warning)',
            }} 
          />
          <Text variant="caption" style={{ color: 'var(--ggui-color-onSurfaceVariant)' }}>
            {lastUpdated 
              ? 'Syncing live: last tick ' + lastUpdated.toLocaleTimeString()
              : 'Connecting to live market feed...'}
          </Text>
        </Stack>
      </Stack>
    </Stack>
  );
}

