            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">WIND</Text>
            <Text weight="semibold" color="var(--ggui-color-onSurface)">
              {windSpeed}
              {' km/h'}
            </Text>
          </Stack>
        </Row>
      </Box>

      <Divider margin={0} />

      {/* Forecast Section */}
      <Box padding="var(--ggui-spacing-4)" style={{ background: 'var(--ggui-color-surfaceVariant, var(--ggui-color-surface-container))' }}>
        <Row justify="between" gap={8}>
          {forecast.slice(0, 5).map((item, index) => (
            <Stack key={index} align="center" gap={8} style={{ flex: 1 }}>
              <Text variant="caption" weight="bold" color="var(--ggui-color-onSurfaceVariant)">
                {item.day || '---'}
              </Text>
              <span style={{ fontSize: 'var(--ggui-font-size-xl)' }} aria-hidden="true">
                {item.icon || getWeatherEmoji(condition)}
              </span>
              <Stack gap={0} align="center">
                <Text weight="bold" style={{ fontSize: 'var(--ggui-font-size-sm)' }}>
                  {item.high !== undefined ? Math.round(item.high) + '\u00B0' : '--'}
                </Text>
                <Text color="var(--ggui-color-onSurfaceVariant)" style={{ fontSize: 'var(--ggui-font-size-xs)' }}>
                  {item.low !== undefined ? Math.round(item.low) + '\u00B0' : '--'}
                </Text>
              </Stack>
            </Stack>
          ))}
        </Row>
      </Box>
    </Card>
  );
}

import React, { useState, useMemo } from 'react';
import { Stack, Text, Card, Input } from '@ggui-ai/design/primitives';

interface Element {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  electronConfiguration?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Array of elements with atomicNumber, symbol, name, atomicWeight, category (kebab-case), electronConfiguration, row, col */
  elements: Element[];
}

const CATEGORY_MAP: Record<string, { label: string; color: string; textColor: string }> = {
  'alkali-metal': { label: 'Alkali Metal', color: 'var(--ggui-color-error-subtle)', textColor: 'var(--ggui-color-onErrorContainer)' },
  'alkaline-earth': { label: 'Alkaline Earth', color: 'var(--ggui-color-warning-subtle)', textColor: 'var(--ggui-color-onWarningContainer)' },
  'transition-metal': { label: 'Transition Metal', color: 'var(--ggui-color-info-subtle)', textColor: 'var(--ggui-color-onInfoContainer)' },
  'post-transition-metal': { label: 'Post-transition Metal', color: 'var(--ggui-color-success-subtle)', textColor: 'var(--ggui-color-onSuccessContainer)' },
  'metalloid': { label: 'Metalloid', color: 'var(--ggui-color-accent-subtle)', textColor: 'var(--ggui-color-onAccentContainer)' },
  'nonmetal': { label: 'Nonmetal', color: 'var(--ggui-color-primary-subtle)', textColor: 'var(--ggui-color-onPrimaryContainer)' },
  'halogen': { label: 'Halogen', color: 'var(--ggui-color-primary-muted)', textColor: 'var(--ggui-color-onSurface)' },
  'noble-gas': { label: 'Noble Gas', color: 'var(--ggui-color-success-muted)', textColor: 'var(--ggui-color-onSurface)' },
  'lanthanide': { label: 'Lanthanide', color: 'var(--ggui-color-surface-variant)', textColor: 'var(--ggui-color-onSurfaceVariant)' },
  'actinide': { label: 'Actinide', color: 'var(--ggui-color-outline-variant)', textColor: 'var(--ggui-color-onSurface)' },
};

export default function PeriodicTable({ elements = [] }: Props) {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedElement, setSelectedElement] = useState<Element | null>(null);

  const filteredElements = useMemo(() => {
    if (!searchTerm) return elements;
    const lowerSearch = searchTerm.toLowerCase();
    return elements.filter((el) => 
      (el.name?.toLowerCase().includes(lowerSearch)) || 
      (el.symbol?.toLowerCase().includes(lowerSearch))
    );
  }, [elements, searchTerm]);

  const categories = Object.keys(CATEGORY_MAP);

  return (
    <Stack direction="column" gap="xl" style={{ width: '100%', padding: 'var(--ggui-spacing-md)' }}>
      {/* Header & Filter */}
      <Stack direction="column" gap="md">
        <Text variant="headline-medium">Periodic Table of Elements</Text>
        <Stack direction="column" gap="xs">
          <Text variant="label-medium" as="label" htmlFor="element-search">Filter Elements</Text>
          <Input label="Filter Elements" id="element-search" placeholder="Search by name or symbol..." value={searchTerm} onChange={setSearchTerm} style={{ maxWidth: 'var(--ggui-spacing-xl-large)' }} />
        </Stack>
      </Stack>

      {/* Legend */}
      <Stack direction="row" gap="md" wrap="wrap">
        {categories.map((cat) => (
          <Stack key={cat} direction="row" align="center" gap="xs">
            <div
              style={{
                width: 'var(--ggui-spacing-md)',
                height: 'var(--ggui-spacing-md)',
                borderRadius: 'var(--ggui-radius-xs)',
                backgroundColor: CATEGORY_MAP[cat].color,
                border: '1px solid var(--ggui-color-outline)',
              }}
            />
            <Text variant="body-small">{CATEGORY_MAP[cat].label}</Text>
          </Stack>
        ))}
      </Stack>

      {/* Grid Container */}
      <div
        style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(18, minmax(0, 1fr))',
          gap: 'var(--ggui-spacing-xs)',
          overflowX: 'auto',
          padding: 'var(--ggui-spacing-xs)',
          background: 'var(--ggui-color-surface-container-low)',
          borderRadius: 'var(--ggui-radius-md)',
        }}
      >
        {filteredElements.map((el) => {
          const categoryStyle = CATEGORY_MAP[el.category || ''] || { color: 'var(--ggui-color-surface-variant)', textColor: 'var(--ggui-color-onSurface)' };
          const isSelected = selectedElement?.atomicNumber === el.atomicNumber;

          return (
            <Card
              key={el.atomicNumber}
              variant={isSelected ? 'outline' : 'flat'}
              onClick={() => setSelectedElement(el)}
              style={{
                gridRow: el.row,
                gridColumn: el.col,
                backgroundColor: categoryStyle.color,
                cursor: 'pointer',
                aspectRatio: '1 / 1',
                padding: 'var(--ggui-spacing-xs)',
                transition: 'transform 0.1s ease-in-out',
                transform: isSelected ? 'scale(1.05)' : 'none',
                zIndex: isSelected ? 10 : 1,
                border: isSelected ? '2px solid var(--ggui-color-primary)' : '1px solid var(--ggui-color-outline-variant)',
                minWidth: '3.5rem',
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                justifyContent: 'center',
              }}
            >
              <Stack direction="column" align="center" justify="center" style={{ height: '100%', position: 'relative', width: '100%' }}>
                <Text
                  variant="label-small"
                  style={{
                    position: 'absolute',
                    top: '0',
                    left: '0',
                    fontSize: '0.625rem',
                    color: categoryStyle.textColor,
                  }}
                >
                  {el.atomicNumber}
                </Text>
                <Text
                  variant="title-medium"
                  style={{
                    fontWeight: 'bold',
                    color: categoryStyle.textColor,
                    lineHeight: '1',
                  }}
                >
                  {el.symbol}
                </Text>
              </Stack>
            </Card>
          );
        })}
      </div>

      {/* Detail Panel */}
      {selectedElement && (
        <Card variant="outline" style={{ padding: 'var(--ggui-spacing-lg)', marginTop: 'var(--ggui-spacing-md)' }}>
          <Stack direction="column" gap="md">
            <Stack direction="row" align="baseline" gap="sm">
              <Text variant="headline-small">{selectedElement.name}</Text>
              <Text variant="title-large" style={{ opacity: 0.7 }}>({selectedElement.symbol})</Text>
            </Stack>

            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: 'var(--ggui-spacing-md)' }}>
              <Stack direction="column">
                <Text variant="label-medium" style={{ color: 'var(--ggui-color-onSurfaceVariant)' }}>Atomic Number</Text>
                <Text variant="body-large">{selectedElement.atomicNumber}</Text>
              </Stack>
              <Stack direction="column">
                <Text variant="label-medium" style={{ color: 'var(--ggui-color-onSurfaceVariant)' }}>Atomic Weight</Text>
                <Text variant="body-large">{selectedElement.atomicWeight} u</Text>
              </Stack>
              <Stack direction="column">
                <Text variant="label-medium" style={{ color: 'var(--ggui-color-onSurfaceVariant)' }}>Category</Text>
                <Text variant="body-large">{CATEGORY_MAP[selectedElement.category || '']?.label || selectedElement.category}</Text>
              </Stack>
              <Stack direction="column">
                <Text variant="label-medium" style={{ color: 'var(--ggui-color-onSurfaceVariant)' }}>Electron Configuration</Text>
                <Text variant="body-large" style={{ wordBreak: 'break-all' }}>{selectedElement.electronConfiguration}</Text>
              </Stack>
            </div>
          </Stack>
        </Card>
      )}
    </Stack>
  );
}

import React, { useState, useEffect } from 'react';
import { Stack, Text, Card } from '@ggui-ai/design/primitives';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<Stock>;
}

/**
 * Real-time Market Dashboard component.
 * Displays a grid of stock prices and updates live via window events.
 */
export default function MarketDashboard({ stocks: initialStocks = [] }: Props) {
  const [stocks, setStocks] = useState<Stock[]>(initialStocks);
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const [isConnected, setIsConnected] = useState(false);

  useEffect(() => {
    if (initialStocks && initialStocks.length > 0) {
      setStocks(initialStocks);
    }
  }, [initialStocks]);

  useEffect(() => {
    const handleData = (event: any) => {
      const detail = event.detail;
      if (detail?.type === 'price-update' && detail.data) {
        setIsConnected(true);
        const { symbol, price, change, changePercent } = detail.data;

        setStocks((prevStocks) =>
          prevStocks.map((s) =>
            s.symbol === symbol
              ? { ...s, price, change, changePercent }
              : s
          )
        );
        setLastUpdated(new Date());
      }
    };

    // Global event listener for agent data stream
    if (typeof addEventListener !== 'undefined') {
      addEventListener('ggui:agent-data', handleData);
    }

    const timer = setTimeout(() => setIsConnected(true), 1500);

    return () => {
      if (typeof removeEventListener !== 'undefined') {
        removeEventListener('ggui:agent-data', handleData);
      }
      clearTimeout(timer);
    };
  }, []);

  const formatPrice = (val?: number) => 
    val ? val.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 }) : '0.00';

  const formatChange = (val?: number) => {
    if (val === undefined) return '0.00';
    return (val > 0 ? '+' : '') + val.toFixed(2);
  };

  return (
    <Stack 
      gap="xl" 
      padding="xl" 
      style={{ 
        backgroundColor: 'var(--ggui-color-surface)', 
        minHeight: '100%',
        color: 'var(--ggui-color-onSurface)'
      }}
    >
      {/* Header */}
      <Stack 
        direction="row" 
        align="center" 
        justify="space-between"
        style={{ 
          borderBottom: '1px solid var(--ggui-color-outlineVariant)', 
          paddingBottom: 'var(--ggui-spacing-md)' 
        }}
      >
        <Stack gap="xs">
          <Text variant="h2" weight="bold">Market Watch</Text>
          <Text size="sm" style={{ color: 'var(--ggui-color-onSurfaceVariant)' }}>
            Real-time equity performance
          </Text>
        </Stack>

        <Stack align="flex-end" gap="xs">
          <Text weight="medium">
            {lastUpdated.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
          </Text>
          <Stack direction="row" align="center" gap="xs">
            <span 
              role="status"
              style={{ 
                width: 'var(--ggui-spacing-sm)', 
                height: 'var(--ggui-spacing-sm)', 
                borderRadius: '50%', 
                backgroundColor: isConnected ? 'var(--ggui-color-success)' : 'var(--ggui-color-warning)'
              }} 
            />
            <Text size="xs" weight="bold">
              {isConnected ? 'LIVE FEED' : 'CONNECTING...'}
            </Text>
          </Stack>
        </Stack>
      </Stack>

      {/* Stock Cards Grid */}
      <Stack 
        direction="row" 
        wrap="wrap" 
        gap="lg" 
        style={{ 
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))',
          width: '100%'
        }}
      >
        {stocks.map((stock) => {
          const isPositive = (stock.change ?? 0) >= 0;
          const statusColor = isPositive 
            ? 'var(--ggui-color-success)' 
            : 'var(--ggui-color-error)';

          return (
            <Card 
              key={stock.symbol} 
              padding="lg" 
              variant="elevated"
              style={{ 
                borderColor: 'var(--ggui-color-outlineVariant)'
              }}
            >
              <Stack gap="lg">
                <Stack direction="row" justify="space-between" align="flex-start">
                  <Stack gap="none">
                    <Text variant="h3" weight="bold">
                      {stock.symbol}
                    </Text>
                    <Text size="sm" style={{ color: 'var(--ggui-color-onSurfaceVariant)' }}>
                      {stock.name}
                    </Text>
                  </Stack>
                </Stack>

                <Stack gap="xs">
                  <Stack direction="row" align="baseline" gap="xs">
                    <Text size="sm" style={{ color: 'var(--ggui-color-onSurfaceVariant)' }}>$</Text>
                    <Text variant="h2" weight="bold">
                      {formatPrice(stock.price)}
                    </Text>
                  </Stack>

                  <Stack direction="row" gap="sm" align="center">
                    <Text 
                      weight="bold" 
                      style={{ color: statusColor }}
                    >
                      {formatChange(stock.change)}
                    </Text>
                    <Text 
                      size="sm" 
                      weight="bold"
                      style={{ 
                        color: statusColor,
                        padding: 'var(--ggui-spacing-xs) var(--ggui-spacing-sm)',
                        backgroundColor: 'var(--ggui-color-surfaceVariant)',
                        borderRadius: 'var(--ggui-radius-sm)',
                        display: 'flex',
                        alignItems: 'center',
                        gap: 'var(--ggui-spacing-xxs)'
                      }}
                    >
                      {isPositive ? '▲' : '▼'} {Math.abs(stock.changePercent ?? 0).toFixed(2) + '%'}
                    </Text>
                  </Stack>
                </Stack>
              </Stack>
            </Card>
          );
        })}
      </Stack>

      {/* Dashboard Footer */}
      <Stack 
        align="center" 
        justify="center" 
        padding="lg"
        style={{ 
          borderTop: '1px solid var(--ggui-color-outlineVariant)',
          marginTop: 'var(--ggui-spacing-xl)'
        }}
      >
        <Text size="xs" style={{ color: 'var(--ggui-color-onSurfaceVariant)', textAlign: 'center' }}>
          Market data provided via agent stream. <br/>
          Last update: {lastUpdated.toLocaleTimeString()} on {lastUpdated.toLocaleDateString()}.
        </Text>
      </Stack>
    </Stack>
  );
}

/** 
 * __GGUI_STREAM_SPEC__
 * {
 *   "events": {
 *     "price-update": {
 *       "schema": {
 *         "type": "object",
 *         "properties": {
 *           "symbol": { "type": "string" },
 *           "price": { "type": "number" },
 *           "change": { "type": "number" },
 *           "changePercent": { "type": "number" }
 *         },
 *         "required": ["symbol", "price", "change", "changePercent"]
 *       }
 *     }
 *   }
 * }
 * __GGUI_STREAM_SPEC_END__
 */

import React, { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  Select,
  Checkbox,
  Button,
  Divider,
  Box,
  Icon,
} from '@ggui-ai/design/primitives';

interface Props {
  avatarOptions: string[];
  roleOptions: string[];
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  onComplete: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

export default function OnboardingWizard(props: Props) {
  const {
    avatarOptions = ['👤', '🚀', '🎨', '💻'],
    roleOptions = ['Developer', 'Designer', 'Manager', 'Other'],
    initialProfile = {},
    onComplete,
  } = props;

  const [step, setStep] = useState(0);
  const [formData, setFormData] = useState({
    name: initialProfile.name ?? '',
    email: initialProfile.email ?? '',
    avatar: initialProfile.avatar ?? (avatarOptions[0] || '👤'),
    role: initialProfile.role ?? '',
    emailNotifications: initialProfile.emailNotifications ?? true,
    theme: initialProfile.theme ?? 'light',
  });

  const isValidEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  const isStep1Valid = formData.name.trim().length > 0 && isValidEmail(formData.email);
  const isStep2Valid = formData.role !== '' && formData.theme !== '';
  const isNextDisabled = (step === 0 && !isStep1Valid) || (step === 1 && !isStep2Valid);

  const handleUpdate = (field: string, value: any) => setFormData(p => ({ ...p, [field]: value }));
  const handleNext = () => setStep(s => s + 1);
  const handleBack = () => setStep(s => s - 1);
  const handleSubmit = () => onComplete && onComplete(formData);

  const progressPct = (step + 1) * 33.3;

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-8)">
      <Card padding="var(--ggui-spacing-8)" shadow="md">
        <Stack gap={32}>
          <Stack gap={16}>
            <Text variant="h2" align="center">Welcome aboard!</Text>
            <Stack gap={12}>
              <Row justify="between" align="center">
                <Text variant="label" weight="semibold">Step {step + 1} of 3</Text>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  {step === 0 ? 'Profile Setup' : step === 1 ? 'Preferences' : 'Review & Confirm'}
                </Text>
              </Row>
              <div style={{ height: 8, background: 'var(--ggui-color-outlineVariant)', borderRadius: 99, overflow: 'hidden' }}>
                <div style={{ height: '100%', width: String(progressPct) + '%', background: 'var(--ggui-color-primary)', borderRadius: 99, transition: 'width 0.3s ease' }} />
              </div>
            </Stack>
          </Stack>

          <Divider />

          <div style={{ minHeight: 320 }}>
            {step === 0 && (
              <Stack gap={24}>
                <Stack gap={8}>
                  <Text as="label" htmlFor="name" variant="label">Name</Text>
                  <Input id="name" label="Name" value={formData.name} onChange={v => handleUpdate('name', v)} required />
                </Stack>
                <Stack gap={8}>
                  <Text as="label" htmlFor="email" variant="label">Email</Text>
                  <Input id="email" label="Email" value={formData.email} onChange={v => handleUpdate('email', v)} error={formData.email && !isValidEmail(formData.email) ? 'Invalid' : undefined} required />
                </Stack>
                <Stack gap={8}>
                  <Text variant="label">Avatar</Text>
                  <Row gap={16} wrap="wrap">
                    {avatarOptions.map(emoji => (
                      <Box
                        key={emoji}
                        padding={12}
                        borderRadius="var(--ggui-shape-radius-lg)"
                        background={formData.avatar === emoji ? 'var(--ggui-color-primary-container)' : 'var(--ggui-color-surface-variant)'}
                        style={{ cursor: 'pointer', border: '2px solid ' + (formData.avatar === emoji ? 'var(--ggui-color-primary)' : 'transparent'), fontSize: '1.5rem', display: 'flex', alignItems: 'center', justifyContent: 'center', minWidth: 64, minHeight: 64 }}
                        onClick={() => handleUpdate('avatar', emoji)}
                        role="button"
                        aria-label={'Select ' + emoji}
                        aria-pressed={formData.avatar === emoji}
                      >{emoji}</Box>
                    ))}
                  </Row>
                </Stack>
              </Stack>
            )}

            {step === 1 && (
              <Stack gap={24}>
                <Select label="Role" placeholder="Select role" value={formData.role} onChange={v => handleUpdate('role', v)} options={roleOptions.map(r => ({ value: r, label: r }))} required />
                <Stack gap={12}>
                  <Text variant="label">Theme</Text>
                  <Row gap={12}>
                    <Button variant={formData.theme === 'light' ? 'primary' : 'outline'} onClick={() => handleUpdate('theme', 'light')} leftIcon={<Icon name="settings" size={16} />} fullWidth>Light</Button>
                    <Button variant={formData.theme === 'dark' ? 'primary' : 'outline'} onClick={() => handleUpdate('theme', 'dark')} leftIcon={<Icon name="menu" size={16} />} fullWidth>Dark</Button>
                  </Row>
                </Stack>
                <Checkbox label="Notifications" checked={formData.emailNotifications} onChange={v => handleUpdate('emailNotifications', v)} />
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={24}>
                <Text variant="h3">Review</Text>
                <Card background="var(--ggui-color-surface-variant)" padding={16} border={false}>
                  <Stack gap={16}>
                    <Row align="center" gap={16}>
                      <Text style={{ fontSize: '48px' }}>{formData.avatar}</Text>
                      <Stack gap={0}>
                        <Text weight="semibold">{formData.name}</Text>
                        <Text variant="bodySmall">{formData.email}</Text>
                      </Stack>
                    </Row>
                    <Divider />
                    <Row justify="between">
                      <Stack gap={4}>
                        <Text variant="caption">Role</Text>
                        <Text>{formData.role}</Text>
                      </Stack>
                      <Stack gap={4} align="end">
                        <Text variant="caption">Theme</Text>
                        <Text>{formData.theme}</Text>
                      </Stack>
                    </Row>
                    <Divider />
                    <Row align="center" gap={8}>
                      <Icon name="check" size={16} color={formData.emailNotifications ? 'var(--ggui-color-success)' : 'var(--ggui-color-outline)'} />
                      <Text variant="bodySmall">Notifications {formData.emailNotifications ? 'enabled' : 'disabled'}</Text>
                    </Row>
                  </Stack>
                </Card>
              </Stack>
            )}
          </div>

          <Divider />

          <Row justify="between" gap={16}>
            <Button variant="outline" onClick={handleBack} disabled={step === 0} leftIcon={<Icon name="chevron-left" size={16} />}>Back</Button>
            {step < 2 ? (
              <Button variant="primary" onClick={handleNext} disabled={isNextDisabled} rightIcon={<Icon name="chevron-right" size={16} />}>Next</Button>
            ) : (
              <Button variant="primary" onClick={handleSubmit} leftIcon={<Icon name="check" size={16} />}>Complete Setup</Button>
            )}
          </Row>
        </Stack>
      </Card>
    </Container>
  );
}

import React from 'react';
import { Card, Stack, Text, Box, Divider, Row } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent({
  city = '—',
  temperature = 0,
  condition = 'Unknown',
  humidity = 0,
  windSpeed = 0,
  unit = 'C',
  forecast = [],
}: Props) {
  const normalizedUnit = unit?.toUpperCase() === 'F' ? 'F' : 'C';
  const windUnit = normalizedUnit === 'F' ? 'mph' : 'km/h';
  const visibleForecast = forecast.slice(0, 5);

  return (
    <Card
      padding={24}
      shadow="md"
      border
      role="group"
      aria-label={'Weather for ' + city}
      style={{
        background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
        borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
        borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
      }}
    >
      <Stack direction="vertical" gap={16} style={{ gap: 'var(--ggui-spacing-4, 16px)' }}>
        <Row justify="between" align="start">
          <Stack direction="vertical" gap={8} style={{ gap: 'var(--ggui-spacing-2, 8px)' }}>
            <Text variant="label" style={{ color: 'var(--ggui-color-onSurfaceVariant, #52525b)' }}>
              {city}
            </Text>
            <Row align="center" gap={8}>
              <Text
                variant="body"
                aria-hidden="true"
                style={{ color: 'var(--ggui-color-primary-600, #0284c7)' }}
              >
                {condition}
              </Text>
              <Text
                variant="body"
                weight="medium"
                style={{ color: 'var(--ggui-color-onSurface, #18181b)' }}
              >
                {condition}
              </Text>
            </Row>
          </Stack>

          <Text
            variant="h1"
            weight="bold"
            style={{ color: 'var(--ggui-color-primary-600, #0284c7)' }}
          >
            {temperature}°{normalizedUnit}
          </Text>
        </Row>

        <Row justify="between" gap={16} wrap>
          <Box
            style={{
              border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
              borderRadius: 'var(--ggui-shape-radius-md, 8px)',
              padding: 'var(--ggui-spacing-2, 8px)',
              minWidth: 120,
              flex: '1 1 140px',
              background: 'var(--ggui-color-surface, #fafafa)',
            }}
          >
            <Stack direction="vertical" gap={4}>
              <Text variant="caption" style={{ color: 'var(--ggui-color-onSurfaceVariant, #52525b)' }}>
                Humidity
              </Text>
              <Text variant="body" weight="semibold" style={{ color: 'var(--ggui-color-onSurface, #18181b)' }}>
                {humidity}%
              </Text>
            </Stack>
          </Box>

          <Box
            style={{
              border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
              borderRadius: 'var(--ggui-shape-radius-md, 8px)',
              padding: 'var(--ggui-spacing-2, 8px)',
              minWidth: 120,
              flex: '1 1 140px',
              background: 'var(--ggui-color-surface, #fafafa)',
            }}
          >
            <Stack direction="vertical" gap={4}>
              <Text variant="caption" style={{ color: 'var(--ggui-color-onSurfaceVariant, #52525b)' }}>
                Wind
              </Text>
              <Text variant="body" weight="semibold" style={{ color: 'var(--ggui-color-onSurface, #18181b)' }}>
                {windSpeed} {windUnit}
              </Text>
            </Stack>
          </Box>
        </Row>

        <Divider style={{ borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)' }} />

        <Box role="list" aria-label="5-day forecast" style={{ overflowX: 'auto' }}>
          {visibleForecast.length === 0 ? (
            <Text variant="caption" style={{ color: 'var(--ggui-color-onSurfaceVariant, #52525b)' }}>
              No forecast data
            </Text>
          ) : (
            <Row justify="between" gap={8} wrap={false}>
              {visibleForecast.map((item, index) => {
                const day = item.day ?? '—';
                const icon = item.icon ?? '•';
                const high = item.high ?? '—';
                const low = item.low ?? '—';

                return (
                  <Box
                    key={(item.day ?? 'day') + '-' + index}
                    role="listitem"
                    style={{
                      border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                      background: 'var(--ggui-color-surface, #fafafa)',
                      borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                      padding: 'var(--ggui-spacing-2, 8px)',
                      minWidth: 72,
                      textAlign: 'center',
                    }}
                  >
                    <Stack direction="vertical" gap={4}>
                      <Text
                        variant="caption"
                        weight="medium"
                        style={{ color: 'var(--ggui-color-onSurfaceVariant, #52525b)' }}
                      >
                        {day}
                      </Text>
                      <Text variant="body" style={{ color: 'var(--ggui-color-onSurface, #18181b)' }}>
                        {icon}
                      </Text>
                      <Text variant="caption" style={{ color: 'var(--ggui-color-onSurfaceVariant, #52525b)' }}>
                        {high}°/{low}°
                      </Text>
                    </Stack>
                  </Box>
                );
              })}
            </Row>
          )}
        </Box>
      </Stack>
    </Card>
  );
}
